INSERT INTO public.sops (slug,title,type,department,outlet,tags,important_rules,steps,sections,notes,published) VALUES
('tula-steps-of-service','Tula Steps of Service','SOP','Food & Beverage','Tula',ARRAY['alcohol','bar','compliance'],'["Reporting to work under the influence or consuming alcohol during work is strictly prohibited.", "Alcohol consumption is only permitted for approved tastings/trainings.", "Tastings are sample portions not exceeding 2 oz per pour.", "Tastings must be scheduled and conducted privately away from guests.", "Only authorized personnel may be behind the bar during business hours.", "Staff may not patronize bar/lounge before/during/after shift without prior approval."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Use alcohol only under approved tasting/training exceptions.</li><li>For tastings, limit pours to 2 oz samples.</li><li>Conduct tastings only for approved staff training or product evaluation.</li><li>Schedule tastings in advance with vendor or management.</li><li>Hold tastings in private area away from guests.</li><li>Allow only bar staff, venue managers, and F&amp;B executives behind bar during business hours.</li><li>Require culinary staff to coordinate with venue management for alcohol transfers used in food prep.</li><li>Require Engineering/IT/Accounting staff to be accompanied by venue management when accessing alcoholic beverages.</li></ul>"}]'::jsonb,NULL,true),
('alcoholic-beverages-and-tastings-sop','Alcoholic Beverages and Tastings SOP','SOP','Food & Beverage','Resort-wide',ARRAY['alcohol','compliance'],'["All equipment must be collected, cleaned, and safely stored.", "Return walkie-talkie to F&B office.", "Report lost & found and damaged/missing items."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Gather lounge chairs, umbrellas, cushions, mats, side tables.</li><li>Close umbrellas carefully and remove from sand.</li><li>Pack sand around poles as needed for safe storage.</li><li>Clean and wipe down furniture/equipment.</li><li>Park ATV in designated area and check fuel/basic safety.</li><li>Turn off and lock ATV if applicable.</li><li>Return walkie-talkie to F&amp;B office.</li><li>Clean beach area of trash/debris/personal items.</li><li>Report lost &amp; found items to supervisor.</li><li>Record damaged/missing chairs in daily log.</li><li>Report guest complaints regarding chairs immediately.</li></ul>"}]'::jsonb,'Review: body content mentions beach/ATV which doesn''t match the alcohol-focused title. Original SOP may have had content mixed up.',true),
('ird-delivery-and-pickup-track-sheet','IRD Delivery and Pick-Up Track Sheet Procedure','Checklist','Food & Beverage','IRD',ARRAY['ird','tracking','logging'],'["Collect walkie-talkie from F&B office and set to Channel 5.", "Inspect ATV for fuel, tire pressure, and safety before use.", "Confirm all guests have left before beginning closing duties."]'::jsonb,'[{"number": 1, "text": "Greet guests warmly upon arrival."}, {"number": 2, "text": "Set up chairs, umbrellas, cabanas, and tables."}, {"number": 3, "text": "Stock towels, water, and amenities."}, {"number": 4, "text": "Inspect all equipment for safety and functionality."}, {"number": 5, "text": "Ensure beach area is clean and free of debris."}, {"number": 6, "text": "Collect walkie-talkie from F&B office and set to Channel 5."}, {"number": 7, "text": "Inspect ATV for fuel, tire pressure, and safety before use."}, {"number": 8, "text": "Use ATV as needed to transport equipment and supplies safely."}, {"number": 9, "text": "Confirm all guests have left the beach area."}, {"number": 10, "text": "Collect and store all equipment (chairs, umbrellas, tables, cabana items)."}, {"number": 11, "text": "Gather and return all service items (towels, trays, menus, coolers)."}, {"number": 12, "text": "Inspect equipment and report any damage or missing items."}, {"number": 13, "text": "Remove trash and debris; wipe down tables and surfaces."}, {"number": 14, "text": "Clean and park ATV in the designated storage area; ensure it is secured."}, {"number": 15, "text": "Bring walkie-talkie back to F&B office."}, {"number": 16, "text": "Ensure beach area is clean, organized, and ready for the next day."}, {"number": 17, "text": "Notify supervisor once closing duties are completed."}]'::jsonb,'[]'::jsonb,NULL,true),
('ird-pickup-sheet-sop','IRD Pick-Up Sheet SOP','Checklist','Food & Beverage','IRD',ARRAY['ird','closing'],'["Confirm all guests have left before closing activities.", "ATV must be cleaned, parked, and secured.", "Notify supervisor after completion."]'::jsonb,'[{"number": 1, "text": "Confirm all guests have left beach area."}, {"number": 2, "text": "Collect/store equipment (chairs, umbrellas, tables, cabana items)."}, {"number": 3, "text": "Gather/return service items (towels, trays, menus, coolers)."}, {"number": 4, "text": "Inspect equipment and report damage/missing items."}, {"number": 5, "text": "Remove trash/debris; wipe tables/surfaces."}, {"number": 6, "text": "Clean and park ATV in designated storage; secure it."}, {"number": 7, "text": "Return walkie-talkie to F&B office."}, {"number": 8, "text": "Ensure beach area is clean, organized, and ready for next day."}, {"number": 9, "text": "Notify supervisor closing duties are complete."}]'::jsonb,'[]'::jsonb,NULL,true),
('ird-room-fob-check-in-out','IRD Room FOB Check-In/Out Procedure','Checklist','Food & Beverage','IRD',ARRAY['ird','fob','security'],'["Set walkie-talkie to Channel 5.", "Inspect ATV safety before use and operate safely."]'::jsonb,'[{"number": 1, "text": "Greet guests warmly upon arrival."}, {"number": 2, "text": "Set up chairs, umbrellas, cabanas, tables."}, {"number": 3, "text": "Stock towels, water, and amenities."}, {"number": 4, "text": "Inspect equipment for safety/functionality."}, {"number": 5, "text": "Ensure beach area is clean and debris-free."}, {"number": 6, "text": "Collect walkie-talkie from F&B office and set Channel 5."}, {"number": 7, "text": "Inspect ATV fuel/tire pressure/safety before use."}, {"number": 8, "text": "Use ATV safely to transport equipment and supplies."}]'::jsonb,'[]'::jsonb,NULL,true),
('pool-bar-tip-pooling-sop','Pool Bar Tip Pooling and Tip-Out SOP','SOP','Food & Beverage','Pool Bar',ARRAY['tips','compensation','pool-bar'],'["Walkie-talkie must be set to Channel 5.", "Inspect equipment and ATV before operations.", "Follow layout and safety spacing for setup."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Retrieve walkie-talkie from F&amp;B office and set Channel 5.</li><li>Collect cleaning tools, chairs, umbrellas, cushions, towels, mats, side tables.</li><li>Arrange lounge chairs per resort layout with proper spacing.</li><li>Inspect chairs for damage and remove/repair defective units.</li><li>Select stable umbrella positions away from high tide/crowds.</li><li>Dig hole as needed, insert umbrella, secure with sand/anchor/sandbags.</li><li>Open umbrellas and tilt into wind (10&ndash;15&deg;).</li><li>Place towels, cushions, mats, and side tables neatly.</li><li>Inspect ATV (fuel, brakes, tires, lights).</li><li>Use ATV only on designated paths for transport.</li><li>Complete final walkthrough confirming setup and working communications.</li></ul>"}]'::jsonb,NULL,true),
('restaurant-allergy-sop','Restaurant Allergy SOP','SOP','Food & Beverage','Tula',ARRAY['allergy','safety','service'],'["Report damage/missing equipment/incidents immediately.", "Operate ATVs safely and on designated paths.", "Keep walkie-talkie communication active.", "Follow all resort safety/hygiene protocols."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Set up and maintain lounge chairs, umbrellas, and beach equipment.</li><li>Operate/store ATV safely.</li><li>Use walkie talkie to communicate with team.</li><li>Keep beach area clean, organized, and safe.</li><li>Greet guests warmly and assist with seating/cabana setup.</li><li>Provide beach amenity/activity/resort information.</li><li>Anticipate guest needs and deliver prompt courteous service.</li><li>Stock towels, water, and amenities at service points.</li><li>Remove used towels, trash, and debris throughout day.</li><li>Inspect equipment condition and safety.</li><li>Rake algae from shoreline as needed.</li><li>Support food and beverage service when applicable.</li><li>Coordinate with housekeeping, F&amp;B, and front office.</li><li>Report guest requests/incidents/feedback promptly.</li><li>Use safe lifting techniques and secure umbrellas/chairs.</li><li>Do not leave umbrellas unattended in high winds.</li><li>Log incidents, damages, and supply shortages before shift end.</li></ul>"}]'::jsonb,'REVIEW: Title says ''Restaurant Allergy SOP'' but body content is about beach operations. Original content appears to have been mismatched. Needs content rewrite.',true),
('tula-opentable-phone-reservation-sop','Tula OpenTable Phone Reservation SOP','Checklist','Food & Beverage','Tula',ARRAY['opentable','reservations','phone'],'["Confirm guests are out of area before shutdown.", "Return walkie-talkie to F&B office.", "Notify supervisor when duties are complete."]'::jsonb,'[{"number": 1, "text": "Confirm all guests have left beach and pool areas."}, {"number": 2, "text": "Collect/store equipment (chairs, umbrellas, cabanas, tables)."}, {"number": 3, "text": "Gather service items (towels, trays, menus, coolers, amenities)."}, {"number": 4, "text": "Inspect equipment and report damage/missing items."}, {"number": 5, "text": "Remove trash/debris and wipe tables/surfaces."}, {"number": 6, "text": "Return all towels to laundry area."}, {"number": 7, "text": "Ensure area is clean, organized, and ready for next day."}, {"number": 8, "text": "Return walkie-talkie to F&B office."}, {"number": 9, "text": "Notify supervisor once all closing duties are completed."}, {"number": 10, "text": "Check with manager for additional tasks before leaving."}, {"number": 11, "text": "Print checklists as needed."}]'::jsonb,'[]'::jsonb,NULL,true),
('ird-am-checklist','IRD AM Checklist','Checklist','Food & Beverage','IRD',ARRAY['ird','am-shift','opening'],'["Guest safety and comfort monitoring is continuous during shift."]'::jsonb,'[{"number": 1, "text": "Greet and assist guests with seating preferences."}, {"number": 2, "text": "Offer towels, water, and amenities promptly."}, {"number": 3, "text": "Monitor guest safety and comfort throughout day."}, {"number": 4, "text": "Maintain cleanliness of pool deck and beach pathways."}, {"number": 5, "text": "Collect used towels and replace with fresh towels as needed."}, {"number": 6, "text": "Check cabanas regularly and restock amenities."}, {"number": 7, "text": "Communicate guest requests to appropriate departments."}]'::jsonb,'[]'::jsonb,NULL,true),
('ird-am-pm-checklist','IRD AM/PM Checklist','Checklist','Food & Beverage','IRD',ARRAY['ird','setup'],'["Collect walkie-talkie from F&B office and set to Channel 5.", "Area must be clean and equipment safe before guest use."]'::jsonb,'[{"number": 1, "text": "Set up chairs, umbrellas, cabanas, and tables."}, {"number": 2, "text": "Stock towels, water, and guest amenities."}, {"number": 3, "text": "Inspect all equipment for safety and functionality."}, {"number": 4, "text": "Ensure beach/pool area is clean and free of debris."}, {"number": 5, "text": "Collect walkie-talkie and set to Channel 5."}]'::jsonb,'[]'::jsonb,NULL,true),
('ird-pm-checklist','IRD PM Checklist','Checklist','Food & Beverage','IRD',ARRAY['ird','pm-shift','closing'],'["Collect walkie-talkie from F&B office and set to Channel 5.", "Guest safety and comfort monitoring is continuous during shift.", "Return walkie-talkie to F&B office at close.", "Notify supervisor once all closing duties are completed."]'::jsonb,'[{"number": 1, "text": "Set up chairs, umbrellas, cabanas, and tables."}, {"number": 2, "text": "Stock towels, water, and guest amenities."}, {"number": 3, "text": "Inspect all equipment for safety and functionality."}, {"number": 4, "text": "Ensure the beach/pool area is clean and free of debris."}, {"number": 5, "text": "Collect walkie-talkie from F&B office and set to Channel 5."}, {"number": 6, "text": "Greet and assist guests with seating preferences."}, {"number": 7, "text": "Offer towels, water, and amenities promptly."}, {"number": 8, "text": "Monitor guest safety and comfort throughout the day."}, {"number": 9, "text": "Maintain cleanliness of pool deck and beach pathways."}, {"number": 10, "text": "Collect used towels and replace with fresh ones as needed."}, {"number": 11, "text": "Check on cabanas regularly and restock amenities."}, {"number": 12, "text": "Communicate guest requests to appropriate departments."}, {"number": 13, "text": "Confirm all guests have left the beach and pool areas."}, {"number": 14, "text": "Collect and store all equipment (chairs, umbrellas, cabanas, tables)."}, {"number": 15, "text": "Gather all service items (towels, trays, menus, coolers, amenities)."}, {"number": 16, "text": "Inspect equipment; report any damage or missing items."}, {"number": 17, "text": "Remove trash and debris; wipe down tables and surfaces."}, {"number": 18, "text": "Return all towels to laundry area."}, {"number": 19, "text": "Ensure beach area is clean, organized, and ready for the next day."}, {"number": 20, "text": "Return walkie-talkie to F&B office."}, {"number": 21, "text": "Ensure beach and pool areas are clean, organized, and ready for the next day."}, {"number": 22, "text": "Notify supervisor once all closing duties are completed."}, {"number": 23, "text": "Check with manager if any additional tasks are needed before leaving."}]'::jsonb,'[]'::jsonb,NULL,true),
('jeevi-closing-checklist','Jeevi Closing Checklist','SOP','Food & Beverage','Jeevi',ARRAY['weather','safety','closing'],'["Make weather call for high wind, lightning proximity, heavy rain/storm forecast, or dangerous high tide.", "Use Channel 5 for team communication.", "Prioritize guest/staff safety over equipment.", "Do not operate ATVs during hazardous weather.", "Reopen only with supervisor confirmation."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Check weather reports at shift start.</li><li>Continuously monitor sky and wind conditions.</li><li>Watch for lightning, gusts, and approaching storms.</li><li>Trigger weather call when thresholds or severe conditions are met.</li><li>Notify beach supervisor immediately.</li><li>Communicate team actions via walkie-talkie Channel 5.</li><li>Inform guests politely and assist relocation as needed.</li><li>Close/remove umbrellas and secure loose items.</li><li>Stack/store lounge chairs.</li><li>Secure mats, cushions, towels, side tables; park ATVs safely.</li><li>Resume operations only after supervisor confirms safe conditions.</li><li>Re-check equipment for damage before reopening.</li></ul>"}]'::jsonb,NULL,true),
('jeevi-opening-closing-checklist','Jeevi Opening & Closing Checklist','SOP','Food & Beverage','Jeevi',ARRAY['mod','shift-release'],'["Team members must check with MOD before completing shift or leaving building.", "MOD must verify responsibilities complete and business levels allow release.", "Unauthorized leaving is subject to discipline up to termination."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>When shift end approaches, check with MOD for release.</li><li>MOD verifies all shift responsibilities are fulfilled.</li><li>MOD confirms business levels allow departure.</li><li>Check with MOD again before leaving building.</li><li>Leave only after explicit authorization.</li></ul>"}]'::jsonb,NULL,true),
('jeevi-opening-checklist','Jeevi Opening Checklist','Checklist','Food & Beverage','Jeevi',ARRAY['opening','am-shift'],'["Lobby coffee must be ready by 6:30 AM."]'::jsonb,'[{"number": 1, "text": "Check floors for dirty plates/pick up used trays."}, {"number": 2, "text": "Refill peanuts at each floor."}, {"number": 3, "text": "Refill salt and pepper shakers."}, {"number": 4, "text": "Prepare roll-ups."}, {"number": 5, "text": "Clean trays."}, {"number": 6, "text": "Organize and thoroughly clean IRD office."}, {"number": 7, "text": "Ensure glasses are available and stocked."}, {"number": 8, "text": "Clean and organize food metal covers."}, {"number": 9, "text": "Print more checklist paper if needed."}, {"number": 10, "text": "Collect amenities from front desk."}, {"number": 11, "text": "Deliver amenities to rooms."}, {"number": 12, "text": "Polish silverware until spotless."}, {"number": 13, "text": "Restock condiments (ketchup, mustard, mayonnaise, jam, honey)."}, {"number": 14, "text": "Restock fridge (dressings etc.)."}, {"number": 15, "text": "Restock to-go cups."}, {"number": 16, "text": "Prepare lobby coffee by 6:30 AM."}, {"number": 17, "text": "Complete print name, signature, and manager sign-off."}]'::jsonb,'[]'::jsonb,NULL,true),
('lala-bar-am-shift-checklist','LaLa Bar AM Shift Checklist (Opening)','Checklist','Food & Beverage','LaLa Bar',ARRAY['opening','am-shift','sign-off-required'],'["AM shift: Lobby coffee must be ready by 6:30 AM.", "PM shift: JEEVI tea must be ready by 4:30 PM.", "Complete print name, signature, and manager sign-off at shift end."]'::jsonb,'[{"number": 1, "text": "Check floors for dirty plates / pick up used trays."}, {"number": 2, "text": "Refill peanuts at each floor."}, {"number": 3, "text": "Refill salt and pepper shakers."}, {"number": 4, "text": "Prepare roll-ups."}, {"number": 5, "text": "Clean trays."}, {"number": 6, "text": "Organize IRD office."}, {"number": 7, "text": "Clean IRD office thoroughly."}, {"number": 8, "text": "Ensure glasses are available and stocked."}, {"number": 9, "text": "Clean and organize food metal covers."}, {"number": 10, "text": "Print more checklist paper if needed."}, {"number": 11, "text": "Collect amenities from front desk."}, {"number": 12, "text": "Deliver amenities to rooms."}, {"number": 13, "text": "Polish silverware until spotless."}, {"number": 14, "text": "Restock condiments: ketchup, mustard, mayonnaise, jam, honey."}, {"number": 15, "text": "Restock fridge (dressings, etc.)."}, {"number": 16, "text": "Restock to-go cups."}, {"number": 17, "text": "AM: Prepare lobby coffee (must be ready by 6:30 AM). PM: Prepare JEEVI tea (must be ready by 4:30 PM)."}, {"number": 18, "text": "Complete print name, signature, and manager sign-off."}]'::jsonb,'[]'::jsonb,NULL,true),
('lala-bar-pm-shift-checklist','LaLa Bar PM Shift Checklist (Closing)','SOP','Food & Beverage','LaLa Bar',ARRAY['closing','pm-shift','logging'],'["Every delivery/pick-up must be logged.", "Use complete required columns for accountability."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Open IRD Delivery and Pick Up Number tracking sheet for date.</li><li>Record date and team member name.</li><li>Record room number and guest name for each delivery.</li><li>Record time of delivery.</li><li>Record time guest called for pick-up when applicable.</li><li>Record pickup team member name.</li><li>Record actual time of pickup.</li><li>Add notes for exceptions/issues.</li></ul>"}]'::jsonb,NULL,true),
('tula-breakfast-lunch-closing-checklist','Tula Breakfast/Lunch Closing Checklist','SOP','Food & Beverage','Tula',ARRAY['closing','ird','tray-pickup'],'["Process is mandatory for all team members handling IRD deliveries and tray removals.", "Guest floors must be checked every 30-45 minutes.", "No tray should remain outside a guest room longer than 30 minutes unattended.", "Guest call-in pick-up must be completed within 15-20 minutes.", "Missing items must be noted and reported before end of shift."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Maintain the IRD Pick-Up Sheet daily at the designated IRD station or host stand.</li><li>For each delivery record: date, room number, guest name, time delivered, call time (if applicable), pick-up time, server name, and notes.</li><li>At delivery, record room number, delivery time, and server name.</li><li>Inform guest about tray removal timing (call IRD or pickup within ~60-90 minutes).</li><li>Check guest floors every 30-45 minutes and remove hallway trays immediately.</li><li>Record actual tray pick-up time on the sheet.</li><li>When a guest calls for pickup, record call time and assign team member immediately.</li><li>Complete pickup within 15-20 minutes and update sheet.</li><li>During pickup verify/return trays, tray jacks, silverware, coffee pots, and condiment sets.</li><li>Report missing equipment/items to management before shift end.</li></ul>"}]'::jsonb,NULL,true),
('tula-breakfast-lunch-opening-checklist','Tula Breakfast/Lunch Opening Checklist','Checklist','Food & Beverage','Tula',ARRAY['opening','breakfast','lunch'],'["JEEVI tea must be ready by 4:30 PM."]'::jsonb,'[{"number": 1, "text": "Check floors for dirty plates/pick up used trays."}, {"number": 2, "text": "Refill peanuts at each floor."}, {"number": 3, "text": "Refill salt and pepper shakers."}, {"number": 4, "text": "Prepare roll-ups."}, {"number": 5, "text": "Clean trays."}, {"number": 6, "text": "Organize and thoroughly clean IRD office."}, {"number": 7, "text": "Ensure glasses are available and stocked."}, {"number": 8, "text": "Clean and organize food metal covers."}, {"number": 9, "text": "Print more checklist paper if needed."}, {"number": 10, "text": "Collect amenities from front desk."}, {"number": 11, "text": "Deliver amenities to rooms."}, {"number": 12, "text": "Polish silverware until spotless."}, {"number": 13, "text": "Restock condiments (ketchup, mustard, mayonnaise, jam, honey)."}, {"number": 14, "text": "Restock fridge (dressings etc.)."}, {"number": 15, "text": "Restock to-go cups."}, {"number": 16, "text": "Prepare JEEVI tea by 4:30 PM."}, {"number": 17, "text": "Complete print name, signature, and manager sign-off."}]'::jsonb,'[]'::jsonb,NULL,true),
('tula-dinner-closing-checklist','Tula Dinner Closing Checklist','SOP','Food & Beverage','Tula',ARRAY['closing','fob','security'],'["FOB movement must be logged with manager initials at out/in.", "Shift (AM/PM) must be identified for each entry."]'::jsonb,'[]'::jsonb,'[{"title": "Procedure", "body_html": "<ul><li>Enter date and employee name.</li><li>Mark applicable shift (AM or PM).</li><li>Record time out when FOB is issued.</li><li>Manager initials time-out authorization.</li><li>Record time in when FOB is returned.</li><li>Manager initials return confirmation.</li></ul>"}]'::jsonb,NULL,true),
('tula-dinner-opening-checklist','Tula Dinner Opening Checklist','Checklist','Food & Beverage','Tula',ARRAY['opening','dinner','pos','cash-handling'],'["Discard expired items and log waste.", "Complete POS close and secure all access points."]'::jsonb,'[{"number": 1, "text": "Empty and wash drip coffee airpots."}, {"number": 2, "text": "Discard expired grab-and-go items."}, {"number": 3, "text": "Record waste log for pastries, food, beverages."}, {"number": 4, "text": "Wipe/sanitize counters and prep surfaces."}, {"number": 5, "text": "Clean espresso machine (backflush, purge steam wand, wipe exterior)."}, {"number": 6, "text": "Clean grinders and empty hoppers."}, {"number": 7, "text": "Wash utensils, pitchers, smallware."}, {"number": 8, "text": "Sanitize fridge handles, POS terminals, high-touch points."}, {"number": 9, "text": "Sweep and mop area."}, {"number": 10, "text": "Refill dairy/syrups/pastries/dry goods for next day."}, {"number": 11, "text": "Stock grab-and-go refrigerator and refill bottled beverages."}, {"number": 12, "text": "Prepare clean ice bins if applicable."}, {"number": 13, "text": "Move desserts freezer\u2192cooler for overnight thaw."}, {"number": 14, "text": "Rotate dates with FIFO and ensure items labeled/covered."}, {"number": 15, "text": "Restock front counter supplies."}, {"number": 16, "text": "Clean pastry case and wash trays."}, {"number": 17, "text": "Clean condiment station."}, {"number": 18, "text": "Dispose trash/recycling and replace liners."}, {"number": 19, "text": "Count cash drawer and match end-of-day report."}, {"number": 20, "text": "Submit closing sales report."}, {"number": 21, "text": "Log out of POS and power down devices."}, {"number": 22, "text": "Turn off lights/music/displays."}, {"number": 23, "text": "Lock refrigerators, cabinets, and shop doors."}, {"number": 24, "text": "Print checklists as needed."}]'::jsonb,'[]'::jsonb,NULL,true),
('spa-concierge-steps-of-service','Spa Concierge Steps of Service','Checklist','Spa & Wellness','Spa Concierge',ARRAY['opening','pos','fifo'],'["Run test shots and ensure espresso calibration before service.", "Apply FIFO/date checks for grab-and-go and pastry items.", "Verify POS login/cash float before opening."]'::jsonb,'[{"number": 1, "text": "Clock in and review daily notes/manager updates."}, {"number": 2, "text": "Turn on music and digital displays."}, {"number": 3, "text": "Unlock storage, fridges, and POS drawers."}, {"number": 4, "text": "Turn on espresso machine, grinders, brewers, warmers."}, {"number": 5, "text": "Run test shots and calibrate."}, {"number": 6, "text": "Prepare drip coffee and refill airpots."}, {"number": 7, "text": "Restock dairy alternatives and other dairy."}, {"number": 8, "text": "Stock syrups, powders, beverage garnishes."}, {"number": 9, "text": "Set up pastry display/grab-and-go case."}, {"number": 10, "text": "Bake fresh pastries/bread, label and record bake times."}, {"number": 11, "text": "Cool baked items and transfer to display."}, {"number": 12, "text": "Follow FIFO when adding pastry items."}, {"number": 13, "text": "Check product dates and rotate FIFO for grab-and-go."}, {"number": 14, "text": "Stock fruit cups, parfaits, desserts, snacks."}, {"number": 15, "text": "Restock bottled beverages/water."}, {"number": 16, "text": "Ensure packaging is clean and labeled."}, {"number": 17, "text": "Clean/sanitize counters and display cases."}, {"number": 18, "text": "Refill napkins, stirrers, lids, sleeves, cutlery, bags."}, {"number": 19, "text": "Stock and clean condiment station."}, {"number": 20, "text": "Check POS updates and log in."}, {"number": 21, "text": "Verify cash float and receipts."}, {"number": 22, "text": "Inspect floor mats/slip hazards."}, {"number": 23, "text": "Empty small trash bins if needed."}, {"number": 24, "text": "Wash/sanitize leftover dishes or utensils."}]'::jsonb,'[]'::jsonb,NULL,true),
('spa-concierge-communication-service-recovery','Spa Concierge — Communication & Service Recovery','Checklist','Spa & Wellness','Spa Concierge',ARRAY['full-day','opening','closing'],'["Run test shots and ensure espresso calibration before service.", "Apply FIFO/date checks for grab-and-go and pastry items.", "Verify POS login and cash float before opening.", "Discard expired items and log waste at close.", "Complete POS close and secure all access points."]'::jsonb,'[{"number": 1, "text": "Clock in and review daily notes / manager updates."}, {"number": 2, "text": "Turn on music and digital displays."}, {"number": 3, "text": "Unlock all storage areas, fridges, and POS drawers."}, {"number": 4, "text": "Turn on espresso machine, grinders, brewers, and warmers."}, {"number": 5, "text": "Run test shots and ensure proper calibration."}, {"number": 6, "text": "Prepare drip coffee and refill airpots."}, {"number": 7, "text": "Restock dairy: whole, skim, non-dairy alternatives, others."}, {"number": 8, "text": "Stock syrups, powders, and beverage garnishes."}, {"number": 9, "text": "Set up pastry display / grab-and-go case."}, {"number": 10, "text": "Bake fresh pastries and bread for the day."}, {"number": 11, "text": "Label and record bake times."}, {"number": 12, "text": "Allow items to cool and transfer to display."}, {"number": 13, "text": "Follow FIFO when adding to pastry case."}, {"number": 14, "text": "Check product dates and rotate FIFO."}, {"number": 15, "text": "Stock fruit cups, parfaits, desserts, and snacks."}, {"number": 16, "text": "Restock bottled beverages and water."}, {"number": 17, "text": "Ensure packaging is clean and labeled."}, {"number": 18, "text": "Clean and sanitize counters and display cases."}, {"number": 19, "text": "Refill napkins, stirrers, lids, sleeves, cutlery, and bags."}, {"number": 20, "text": "Ensure condiment station is fully stocked and clean."}, {"number": 21, "text": "Check POS system for updates and log in."}, {"number": 22, "text": "Verify cash float and receipts."}, {"number": 23, "text": "Inspect floor mats; remove slip hazards."}, {"number": 24, "text": "Empty small trash bins from previous night if needed."}, {"number": 25, "text": "Wash and sanitize any leftover dishes or utensils."}, {"number": 26, "text": "Empty and wash drip coffee airpots."}, {"number": 27, "text": "Discard any expired grab-and-go items."}, {"number": 28, "text": "Record waste log for pastries, food, and beverages."}, {"number": 29, "text": "Wipe down and sanitize all counters and prep surfaces."}, {"number": 30, "text": "Clean espresso machine (backflush, steam wand purge, wipe exterior)."}, {"number": 31, "text": "Clean grinders and empty hoppers."}, {"number": 32, "text": "Wash all utensils, pitchers, and smallware."}, {"number": 33, "text": "Sanitize fridge handles, POS terminals, and high-touch points."}, {"number": 34, "text": "Sweep and mop entire area."}, {"number": 35, "text": "Refill dairy, syrups, pastries (covered), and dry goods."}, {"number": 36, "text": "Stock grab-and-go refrigerator with next-day items."}, {"number": 37, "text": "Refill bottled beverages."}, {"number": 38, "text": "Prepare clean ice bins if applicable."}, {"number": 39, "text": "Move required desserts from freezer to cooler to thaw safely overnight."}, {"number": 40, "text": "Check dates and rotate using FIFO; ensure all items are labeled and covered."}, {"number": 41, "text": "Restock napkins, lids, stirrers, cutlery, and bags."}, {"number": 42, "text": "Clean pastry case and remove trays for washing."}, {"number": 43, "text": "Check and clean condiment station."}, {"number": 44, "text": "Dispose of all trash and recycling; replace liners."}, {"number": 45, "text": "Count cash drawer and match end-of-day report."}, {"number": 46, "text": "Submit closing sales report."}, {"number": 47, "text": "Log out of POS and power down devices."}, {"number": 48, "text": "Turn off lights, music, and displays."}, {"number": 49, "text": "Lock refrigerators, cabinets, and shop doors."}]'::jsonb,'[]'::jsonb,NULL,true),
('spa-concierge-professional-standards','Spa Concierge — Professional Standards & Conduct','Checklist','Spa & Wellness','Spa Concierge',ARRAY['bar-service','cash-handling'],'["Verify opening cash bank if applicable.", "All garnishes must be labeled/dated.", "Communicate handover status to PM shift."]'::jsonb,'[{"number": 1, "text": "Unlock bar and turn on music/POS."}, {"number": 2, "text": "Check cleanliness of bar top, back bar, floors."}, {"number": 3, "text": "Set mats, napkins, coasters, straws."}, {"number": 4, "text": "Verify starting cash bank."}, {"number": 5, "text": "Fill ice bins."}, {"number": 6, "text": "Prepare fresh garnishes (lemon, lime, orange, cherries, olives, mint, others)."}, {"number": 7, "text": "Label/date garnish containers."}, {"number": 8, "text": "Prepare syrups and house mixes."}, {"number": 9, "text": "Restock liquor to par."}, {"number": 10, "text": "Check/clean pour spouts."}, {"number": 11, "text": "Restock wine and chill whites/sparkling."}, {"number": 12, "text": "Stock beer coolers/check draft system."}, {"number": 13, "text": "Restock napkins, straws, disposables."}, {"number": 14, "text": "Confirm specialty cocktail ingredients."}, {"number": 15, "text": "Polish glassware."}, {"number": 16, "text": "Set service bar for restaurant orders."}, {"number": 17, "text": "Review VIPs, groups, events/BEO, and 86 items."}, {"number": 18, "text": "During shift: keep bar clean, refill ice/garnish, engage guests, support service, monitor liquor levels."}, {"number": 19, "text": "At AM handover: communicate low inventory, open tabs/pending checks, VIP/special situations, and ensure bar is organized."}]'::jsonb,'[]'::jsonb,NULL,true),
('spa-concierge-end-of-day-closing','Spa Concierge End-of-Day Closing Checklist','Checklist','Spa & Wellness','Spa Concierge',ARRAY['closing','bar-service','cash-handling'],'["Follow responsible alcohol service; monitor intoxication.", "Dump/clean ice bins per health code.", "Lock liquor and bar access at end of shift."]'::jsonb,'[{"number": 1, "text": "At shift setup: check garnish levels, restock liquor/beer, confirm polished glassware, review events/reservations, turn on music."}, {"number": 2, "text": "During shift: maintain cleanliness, monitor intoxication, refill ice/garnish, track high-volume items, support team."}, {"number": 3, "text": "Clean/sanitize bar top, back bar, service stations."}, {"number": 4, "text": "Remove and wash bar mats."}, {"number": 5, "text": "Wash/polish/store glassware."}, {"number": 6, "text": "Clean sinks and drains."}, {"number": 7, "text": "Sweep and mop bar area."}, {"number": 8, "text": "Dump and clean ice bins."}, {"number": 9, "text": "Secure liquor; lock cabinets and coolers."}, {"number": 10, "text": "Count cash drawer and reconcile to POS."}, {"number": 11, "text": "Submit closing paperwork."}, {"number": 12, "text": "Turn off equipment, music, and lights."}, {"number": 13, "text": "Lock bar before leaving."}]'::jsonb,'[]'::jsonb,NULL,true),
